BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name ?ownerName WHERE {
  ?elem vocab:NamedElement_name ?name .
  FILTER(
    CONTAINS(LCASE(STR(?name)), LCASE("maintenance alignment duration trade study"))
  )
  ?elem rdf:type ?type .
  OPTIONAL {
    ?elem vocab:Element_owner ?owner .
    OPTIONAL { ?owner vocab:NamedElement_name ?ownerName . }
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name ?owner ?ownerType WHERE {
  ?elem rdf:type ?type ;
        vocab:NamedElement_name ?name .
  FILTER(STR(?name) = "Maintenance Alignment duration trade study")
  OPTIONAL { ?elem vocab:Element_owner ?owner .
             ?owner rdf:type ?ownerType . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name WHERE {
  ?elem rdf:type ?type ;
        vocab:NamedElement_name ?name .
  FILTER(
    CONTAINS(LCASE(STR(?name)), LCASE("maintenance alignment")) &&
    CONTAINS(LCASE(STR(?name)), LCASE("duration trade study"))
  )
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?child ?childType ?childName WHERE {
  BIND(<http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::10%20Analysis::Trade%20studies::Maintenance%20Alignment%20Trade%20Study%20Analysis::Trade%20Study%20Definition::Maintenance%20Alignment%20duration%20trade%20study> AS ?trade)
  ?trade rdf:type ?tradeType .
  OPTIONAL { ?trade vocab:NamedElement_name ?tradeName . }
  OPTIONAL { ?trade vocab:Element_ownedElement+ ?child . }
  OPTIONAL { ?child rdf:type ?childType . }
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }
}
LIMIT 25
